// Cal.com webhook payload shape (per Cal.com docs):
//   {
//     triggerEvent: 'BOOKING_CREATED' | 'BOOKING_RESCHEDULED' |
//                   'BOOKING_CANCELLED' | 'MEETING_ENDED' | ...
//     createdAt: ISO string,
//     payload: {
//       type: 'audit-consult' (the event-type slug),
//       title: '...',
//       description: '...',
//       startTime: ISO,
//       endTime: ISO,
//       organizer: { email, name, timeZone },
//       attendees: [{ email, name, timeZone }],
//       location: '...',
//       additionalNotes: '...',
//       uid: '...',
//     }
//   }
//
// n8n's webhook node wraps this under 'body' by default.

const body = $input.first().json.body || $input.first().json;
const event = body?.triggerEvent || 'BOOKING';
const p = body?.payload || {};

const attendeeSummary = (p.attendees || [])
  .map(a => `${a.name || '(no name)'} <${a.email || '(no email)'}>`)
  .join(', ') || '_(no attendees)_';

// Format the emoji + verb per event
const styles = {
  BOOKING_CREATED:     [':spiral_calendar_pad:', 'New booking'],
  BOOKING_RESCHEDULED: [':arrows_counterclockwise:', 'Rescheduled'],
  BOOKING_CANCELLED:   [':x:',                     'Cancelled'],
  MEETING_ENDED:       [':white_check_mark:',       'Meeting ended'],
};
const [emoji, verb] = styles[event] || [':question:', event];

// Nice human time — try to render in the organizer's TZ if provided
const startTime = p.startTime || '';
const tzHint = p.organizer?.timeZone ? ` (${p.organizer.timeZone})` : '';

const message = [
  `${emoji} **${verb}** — *${p.title || p.type || 'booking'}*`,
  `**When:** ${startTime}${tzHint}`,
  p.location ? `**Where:** ${p.location}` : '',
  `**Attendees:** ${attendeeSummary}`,
  p.additionalNotes ? `\n_Notes:_ ${String(p.additionalNotes).slice(0, 300)}` : '',
  p.uid ? `\n_uid:_ \`${p.uid}\`` : ''
].filter(Boolean).join('\n');

return [{ json: { message, event, uid: p.uid || '', type: p.type || '' } }];
